{{ $json.summary.key_events.map((e, i) => { const srcs = Array.isArray(e.sources) && e.sources.length > 0 ? ' [sources: ' + e.sources.map(s => s.source_name).join(', ') + ']' : ''; return `${i+1}. ${e.title} (importance: ${e.importance_score}) — ${e.significance}${srcs}`; }).join('\n') }}

