parameters.jsCode:
// Extract and validate the article Markdown from the AI response.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Execute Workflow Trigger').first().json;

const article_md = rawContent.trim();

if (article_md.length < 200) {
  throw new Error(`AI article too short for ${ctx.topic_slug}/${ctx.date_key}: ${article_md.length} chars. Minimum 200.`);
}

if (!article_md.startsWith('#')) {
  throw new Error(`AI article does not start with a Markdown heading for ${ctx.topic_slug}/${ctx.date_key}.`);
}

return [{ json: { ...ctx, article_md } }];
